#include <check.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>
#include <setjmp.h>
#include <signal.h>

/*
 * We simulate the vulnerable pattern: a fixed-size GUID buffer and a safe
 * copy function that enforces bounds. The invariant is that no matter what
 * adversarial GUID string a device reports, the destination buffer must never
 * be overflowed — i.e., the copy must be bounded.
 *
 * The safe implementation uses strncpy + explicit null termination.
 * The test verifies that after copying any adversarial input, the destination
 * buffer's content is always null-terminated within bounds and the canary
 * bytes placed immediately after the buffer are never corrupted.
 */

#define GUID_BUFFER_SIZE 64  /* typical fixed-size GUID buffer */
#define CANARY_SIZE      16
#define CANARY_BYTE      0xAB

/*
 * Safe copy function that should replace the vulnerable strcpy.
 * This is what the fixed code MUST do.
 */
static void safe_guid_copy(char *dst, size_t dst_size, const char *src)
{
    if (!dst || dst_size == 0) return;
    strncpy(dst, src, dst_size - 1);
    dst[dst_size - 1] = '\0';
}

/*
 * Helper: build a string of given length filled with a repeated character.
 * Caller must free.
 */
static char *make_string(size_t len, char fill)
{
    char *s = (char *)malloc(len + 1);
    if (!s) return NULL;
    memset(s, fill, len);
    s[len] = '\0';
    return s;
}

